head.script:
scwin.initData = {
	"chart" : {
		"chartUnit" : 10,
		"intervalCount" : 5,
	},
	"observeEvent" : false
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSPN3000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();

	//ecsLib.setChartResizeObserver(this);
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	dmaSearchParam.set("endDt", utilLib.getCurrentDate("yyyyMM"));
	dmaSearchParam.set("strtDt", utilLib.addMonth(utilLib.getCurrentDate("yyyyMM"), -12));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("deptCd", "ALL");
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	var endDate = dmaSearchParam.get("endDt");
	var strtDate = utilLib.addMonth(endDate, -12);
	dmaSearchParam.set("strtDt", strtDate)
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	if (String(endDate).length != 6) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var action = "";
	var resData = "";
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		action = "pn/prvyysammversusprdctnsttus/retrieve-prvyy-samm-versus-prdctn-sttus-setcsc.do"
		resData = dltPrvyySammVersusPrdctnSttusSetcscList;
	} else if (tabIdx == 1) {
		action = "pn/prvyysammversusprdctnsttus/retrieve-prvyy-samm-versus-prdctn-sttus-dept.do"
		resData = dltPrvyySammVersusPrdctnSttusDeptList;
	}

	var option = {
		action : action
			+ queryString,
		method : "get",
		resData : resData,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	var endDate = dmaSearchParam.get("endDt");
	var strtDate = dmaSearchParam.get("strtDt");

	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		grdPrvyySammVersusPrdctnSttusSetcscList.setHeaderValue("hThsyyPrdctnEpwr", endDate.substr(0, 4) + "." + endDate.substr(4, 2) + " 전력 생산량(kWh)");
		grdPrvyySammVersusPrdctnSttusSetcscList.setHeaderValue("hPrvyyPrdctnEpwr", strtDate.substr(0, 4) + "." + strtDate.substr(4, 2) + " 전력 생산량(kWh)");
		if (dltPrvyySammVersusPrdctnSttusSetcscList.getAllJSON().length) {
			grdPrvyySammVersusPrdctnSttusSetcscList.setFocusedCell(0, 0);
		}
	} else if (tabIdx == 1) {
		grdPrvyySammVersusPrdctnSttusDeptList.setHeaderValue("hThsyyPrdctnEpwr", endDate.substr(0, 4) + "." + endDate.substr(4, 2) + " 전력 생산량(kWh)");
		grdPrvyySammVersusPrdctnSttusDeptList.setHeaderValue("hPrvyyPrdctnEpwr", strtDate.substr(0, 4) + "." + strtDate.substr(4, 2) + " 전력 생산량(kWh)");
		if (dltPrvyySammVersusPrdctnSttusDeptList.getAllJSON().length) {
			grdPrvyySammVersusPrdctnSttusDeptList.setFocusedCell(0, 0);
		}
	}
	scwin.grdPrvyySammVersusPrdctnSttusList_oncellclick(0, 0);
};

/**
 * cell 클릭 시 차트 데이터 조회 실행한다.
 * @param
 * @return
 */
scwin.grdPrvyySammVersusPrdctnSttusList_oncellclick = function(row, col) {
	var endDate = dmaSearchParam.get("endDt");
	var strtDate = dmaSearchParam.get("strtDt");
	var rowData = "";
	var cellData = "";
	var action = "";
	var resData = "";

	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("deptCd");

	var action = "";
	var resData = "";
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		rowData = grdPrvyySammVersusPrdctnSttusSetcscList.getRowJSON(row);
		cellData = grdPrvyySammVersusPrdctnSttusSetcscList.getCellData(row, "cmmnCd");
		action = "pn/prvyysammversusprdctnsttus/retrieve-prvyy-samm-versus-prdctn-sttus-setcsc-chart.do"
		resData = dltPrvyySammVersusPrdctnSttusSetcscChartList;
		ecsSetcscDivCd = cellData;
	} else if (tabIdx == 1) {
		rowData = grdPrvyySammVersusPrdctnSttusDeptList.getRowJSON(row);
		cellData = grdPrvyySammVersusPrdctnSttusDeptList.getCellData(row, "deptCd");
		action = "pn/prvyysammversusprdctnsttus/retrieve-prvyy-samm-versus-prdctn-sttus-dept-chart.do"
		resData = dltPrvyySammVersusPrdctnSttusDeptChartList;
		ecsChrgDeptId = cellData;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&endDt=${endDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var option = {
		action : action
			+ queryString,
		method : "get",
		resData : resData,
		success : "scwin.inqireChartCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 차트 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireChartCallback = function() {
	var tabIdx = tabControl.getSelectedTabIndex();
	if (tabIdx == 0) {
		// 발전원별 차트 생성
		scwin.setChartSetcsc();
	} else if (tabIdx == 1) {
		// 부서별 차트 생성
		scwin.setChartDept();
	}
}

/**
 * 탭 변경에 따라 조회
 * @param
 * @return
 */
scwin.tabControl_ontabclick = function(tabID, idx) {
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("deptCd", "ALL");
	acbBasin.setSelectedIndex(0);
	acbSetcsc.setSelectedIndex(0);
	acbDept.setSelectedIndex(0);

	if (idx == 0) {
	} else if (idx == 1) {
		if (dltPrvyySammVersusPrdctnSttusDeptList.getAllJSON().length < 1) {
			scwin.btnInqire_onclick();
		}
	}
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param info
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	var ecsSetcscDivCd = info.newValue;
	dmaSearchParam.set("setcscCd", ecsSetcscDivCd);
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");

	var queryString = `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;

	var option = {
		action : "zz/cmmn/retrieve-prdctn-cnd.do?cnd=dept"
			+ queryString,
		method : "get",
		resData : dltAutoCondition3,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("deptCd", "ALL");
};

scwin.acbMngDept_onviewchange = function(info) {
	dmaSearchParam.set("deptCd", info.newValue);
};

/**
 * 그리드 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplZeroFrmt = function(value) {
	return ecsLib.dsplZeroFrmt(value, 1);
};

/**
 * 그리드 합계 소수점 첫째자리까지 표시 한다.
 * @param value
 * @return
 */
scwin.dsplFrmt = function(value) {
	return ecsLib.dsplFrmt(value, 1);
};
//============================================================================================
// 차트
//============================================================================================
/**
 * 발전원별 차트를 생성
 */
scwin.setChartSetcsc = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerSetcsc";
	rMateChartH5.create($p.id + "chartSetcsc", grpPrdctnSttusSetcscChart.getID(), chartVars, "100%", "100%");
};

/**
* 발전원별 차트 설정
*/
scwin.chartReadyHandlerSetcsc = function(id) {
	var chartData = [];
	var dataList = dltPrvyySammVersusPrdctnSttusSetcscChartList.getAllJSON();
	var endDate = dmaSearchParam.get("endDt");

	for (var idx = 0; idx < dataList.length; idx++) {
		var obj = {
			"name" : dataList[idx].elcpwstnNm,
			"thsyyPrdctnEpwr" : dataList[idx].thsyyPrdctnEpwr,
			"prvyyPrdctnEpwr" : dataList[idx].prvyyPrdctnEpwr,
			"achivRt" : dataList[idx].achivRt
		}
		chartData.push(obj);
	}

	var maxThsyyData = chartData.reduce((max, obj) => Math.max(max, obj.thsyyPrdctnEpwr), 0);
	var maxPrvyyData = chartData.reduce((max, obj) => Math.max(max, obj.prvyyPrdctnEpwr), 0);
	var maxData = maxThsyyData > maxPrvyyData ? maxThsyyData : maxPrvyyData;

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.intervalCount) / chartUnit) * chartUnit;

	var index = grdPrvyySammVersusPrdctnSttusSetcscList.getFocusedRowIndex();
	var setcscNm = grdPrvyySammVersusPrdctnSttusSetcscList.getCellData(index, "setcscNm");
	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '<Options>'
		+ '	<Caption text="' + setcscNm + ' 생산전력 현황" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '	<Legend defaultMouseOverAction="false" />'
		+ '</Options>'
		+ '<NumberFormatter id="numFmt" useThousandsSeparator="true"/>'
		+ '<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '	<horizontalAxis>'
		+ '		<CategoryAxis id="hAxis" categoryField="name" padding="0.7"/>'
		+ '	</horizontalAxis>'
		+ '	<verticalAxis>'
		+ '		<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="kWh"/>'
		+ '	</verticalAxis>'
		+ '<series>'
		+ '	<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '	<series>'
		+ '	<Column2DSeries yField="prvyyPrdctnEpwr" displayName="' + (Number(endDate.substr(0, 4)) - 1) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor1 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	<Column2DSeries yField="thsyyPrdctnEpwr" displayName="' + endDate.substr(0, 4) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor2 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	</series>'
		+ '	</Column2DSet>'
		+ '	<Line2DSeries yField="achivRt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="증감률(%)" labelPosition="up">'
		+ '		<stroke>'
		+ '			<Stroke color="#F9BD03" weight="3"/>'
		+ '		</stroke>'
		+ '	<lineStroke>'
		+ '		<Stroke color="#F9BD03" weight="3"/>'
		+ '			</lineStroke>'
		+ '		<verticalAxis>'
		+ '	<LinearAxis id="vAxis2" formatter="{numFmt}" title="%"/>'
		+ '		</verticalAxis>'
		+ '			<showDataEffect>'
		+ '				<SeriesInterpolate/>'
		+ '			</showDataEffect>'
		+ '		</Line2DSeries>'
		+ '	</series>'
		+ '		<verticalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '			<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		</verticalAxisRenderers>'
		+ '		<horizontalAxisRenderers>'
		+ '			<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '		</horizontalAxisRenderers>'
		+ '</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

/**
 * 부서별 차트를 생성
 */
scwin.setChartDept = function() {
	var chartVars = "rMateOnLoadCallFunction=" + $p.id + "scwin.chartReadyHandlerDept";
	rMateChartH5.create($p.id + "chartDept", grpPrdctnSttusDeptChart.getID(), chartVars, "100%", "100%");
};

/**
* 부서별 차트 설정
*/
scwin.chartReadyHandlerDept = function(id) {
	var chartData = [];
	var dataList = dltPrvyySammVersusPrdctnSttusDeptChartList.getAllJSON();
	var endDate = dmaSearchParam.get("endDt");

	for (var idx = 0; idx < dataList.length; idx++) {
		var obj = {
			"name" : dataList[idx].elcpwstnNm,
			"thsyyPrdctnEpwr" : dataList[idx].thsyyPrdctnEpwr,
			"prvyyPrdctnEpwr" : dataList[idx].prvyyPrdctnEpwr,
			"achivRt" : dataList[idx].achivRt
		}
		chartData.push(obj);
	}

	var maxThsyyData = chartData.reduce((max, obj) => Math.max(max, obj.thsyyPrdctnEpwr), 0);
	var maxPrvyyData = chartData.reduce((max, obj) => Math.max(max, obj.prvyyPrdctnEpwr), 0);
	var maxData = maxThsyyData > maxPrvyyData ? maxThsyyData : maxPrvyyData;

	var chartUnit = Math.max(scwin.initData.chart.chartUnit, Math.pow(10, String(maxData.toFixed(0)).length - 2));
	var interval = Math.ceil((maxData / scwin.initData.chart.intervalCount) / chartUnit) * chartUnit;

	var index = grdPrvyySammVersusPrdctnSttusDeptList.getFocusedRowIndex();
	var deptNm = grdPrvyySammVersusPrdctnSttusDeptList.getCellData(index, "deptNm");
	var solidColor1 = ecsLib.getSkinColors().chartSolidColor1;
	var solidColor2 = ecsLib.getSkinColors().chartSolidColor3;

	var layoutStr =
		'<rMateChart backgroundColor="#FFFFFF" borderStyle="none">'
		+ '<Options>'
		+ '	<Caption text="' + deptNm + ' 생산전력 현황" textAlign="center" paddingTop="4.8" paddingRight="3.2" paddingBottom="4.8" paddingLeft="9.6" fontWeight="bold" fontSize="1rem" />'
		+ '	<Legend defaultMouseOverAction="false" />'
		+ '</Options>'
		+ '	<NumberFormatter id="numFmt" useThousandsSeparator="true" />'
		+ '<Combination2DChart showDataTips="true" dataTipDisplayMode="axis">'
		+ '	<horizontalAxis>'
		+ '		<CategoryAxis id="hAxis" categoryField="name" padding="0.7"/>'
		+ '	</horizontalAxis>'
		+ '	<verticalAxis>'
		+ '		<LinearAxis id="vAxis1" interval="' + interval + '" formatter="{numFmt}" title="kWh"/>'
		+ '	</verticalAxis>'
		+ '	<series>'
		+ '	<Column2DSet type="clustered" maxColumnWidth="25">'
		+ '	<series>'
		+ '	<Column2DSeries yField="prvyyPrdctnEpwr" displayName="' + (Number(endDate.substr(0, 4)) - 1) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor1 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	<Column2DSeries yField="thsyyPrdctnEpwr" displayName="' + endDate.substr(0, 4) + "년" + endDate.substr(4, 2) + '월(kWh)">'
		+ '		<fill>'
		+ '			<SolidColor color="' + solidColor2 + '"/>'
		+ '		</fill>'
		+ '		<showDataEffect>'
		+ '			<SeriesInterpolate />'
		+ '		</showDataEffect>'
		+ '	</Column2DSeries>'
		+ '	</series>'
		+ '	</Column2DSet>'
		+ '		<Line2DSeries yField="achivRt" radius="4.5" itemRenderer="CircleItemRenderer" displayName="증감률(%)" labelPosition="up">'
		+ '			<stroke>'
		+ '				<Stroke color="#F9BD03" weight="3"/>'
		+ '			</stroke>'
		+ '			<lineStroke>'
		+ '				<Stroke color="#F9BD03" weight="3"/>'
		+ '			</lineStroke>'
		+ '			<verticalAxis>'
		+ '				<LinearAxis id="vAxis2" formatter="{numFmt}" title="%"/>'
		+ '			</verticalAxis>'
		+ '			<showDataEffect>'
		+ '				<SeriesInterpolate/>'
		+ '			</showDataEffect>'
		+ '		</Line2DSeries>'
		+ '	</series>'
		+ '	<verticalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{vAxis1}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '		<Axis2DRenderer axis="{vAxis2}" verticalAxisTitleAlignment="vertical" showLine="false" />'
		+ '	</verticalAxisRenderers>'
		+ '	<horizontalAxisRenderers>'
		+ '		<Axis2DRenderer axis="{hAxis}" showLine="true" labelRotation="45" canDropLabels="false" canStagger="true"/>'
		+ '	</horizontalAxisRenderers>'
		+ '</Combination2DChart>'
		+ '</rMateChart>';

	document.getElementById(id).setLayout(layoutStr);
	document.getElementById(id).setData(chartData);
};

//============================================================================================
// 엑셀
//============================================================================================
/**
 * 그리드의 내용을 엑셀로 다운로드 한다.
 * @return
 */
scwin.btnDownExcel_onclick = function() {
	var menuNm = $p.getComponentById("wfm_title").scope.$p.getComponentById("tbxScreenTitle").getValue();
	var subTitleNm1 = document.getElementById($p.id + "tabControl_tab_tabMenu1_tabHTML").title;
	var subTitleNm2 = document.getElementById($p.id + "tabControl_tab_tabMenu2_tabHTML").title;
	var tabIdx = tabControl.getSelectedTabIndex();

	if (tabIdx == 0) {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 6,
			text 		: `${menuNm}_` + `${subTitleNm1}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPrvyySammVersusPrdctnSttusSetcscList, {
			fileName : `${menuNm}_` + `${subTitleNm1}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true
		}, infoArr);
	} else if (tabIdx == 1) {
		// 엑셀 내부 타이틀 추가_240105
		var infoArr = [];
		var infoObj = {
			rowIndex 	: 0,
			colIndex 	: 0,
			rowSpan 	: 0,
			colSpan 	: 6,
			text 		: `${menuNm}_` + `${subTitleNm2}`,
			textAlign 	: "left"
		};
		infoArr.push(infoObj);

		comLib.downloadExcel(grdPrvyySammVersusPrdctnSttusDeptList, {
			fileName : `${menuNm}_` + `${subTitleNm2}.xlsx`,
			type : 1,
			autoSizeColumn : true,
			useDataFormat: true,
			applyDataFormat : true
		}, infoArr);
	}
};
